const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/);
if(input.length===0) process.exit();
let pos=0;
const T=parseInt(input[pos++],10);
let res=[];
for(let i=0;i<T;i++){
  const N=parseInt(input[pos++],10);
  let msb=0,temp=N;
  while(temp>1){temp>>=1; msb++;}
  const lsb=N&1;
  res.push(`${msb} ${lsb}`);
}
console.log(res.join('\n'));
